const fs = require\('fs'\);
const sharp = require\('sharp'\);
const html = fs.readFileSync\('./lockdown-deploy/index.html','utf8'\);

// Check a few key sprite dimensions
async function check\(\) {
  // Extract a few sprites
  const keys = ['marcus_idle','adele_idle','yuki_idle','marcus_win','adele_win'];
  for \(const key of keys\) {
    const regex = new RegExp\('\\"' + key + '\\":\\"data:image/webp;base64,\([^\\"]+\)\\"'\);
    const m = html.match\(regex\);
    if \(m\) {
      const buf = Buffer.from\(m[1],'base64'\);
      const meta = await sharp\(buf\).metadata\(\);
      console.log\(key + ': ' + meta.width + 'x' + meta.height + ' \(' + Math.round\(m[1].length/1024\) + 'KB\)'\);
    } else {
      console.log\(key + ': NOT FOUND'\);
    }
  }
  // Also check artwork
  const artKeys = ['artwork_adele_portrait','artwork_marcus_portrait','artwork_closedguard_marcus_top'];
  for \(const key of artKeys\) {
    const regex = new RegExp\('\\"' + key + '\\":\\"data:image/webp;base64,\([^\\"]+\)\\"'\);
    const m = html.match\(regex\);
    if \(m\) {
      const buf = Buffer.from\(m[1],'base64'\);
      const meta = await sharp\(buf\).metadata\(\);
      console.log\(key + ': ' + meta.width + 'x' + meta.height + ' \(' + Math.round\(m[1].length/1024\) + 'KB\)'\);
    }
  }
}
